#include <bits/stdc++.h>
using namespace std;

int n, a[1005], k, minn = INT_MIN, maxn = 0;

bool check(int x) {
    int cnt = 1, sum = 0;
    for (int i = 0; i < n; i++) {
        sum += a[i];
        if (sum > x) {
            cnt++;
            sum = a[i];
        }
        // cout << sum << ' ' << cnt << endl;
    }
    return (cnt <= k);
}

int find() {
    int l = minn, r = maxn;
    int mid = (l + r) >> 1;
    while (l < r) {
        if (check(mid)) {
            r = mid;
        }
        else {
            l = mid + 1;
        }
        mid = (l + r) >> 1;
    }
    return mid;
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
        maxn += a[i];
        minn = max(minn, a[i]);
    }
    cin >> k;
    cout << find();
    return 0;
}
